import { d3_merge, d3_extent } from '../../core/d3-constants';
import { ScaleRegistry } from '../scale-registry';
import { defined, pick } from '../../utils/zcutils';
import { spliceMinMaxToArray } from '../operators/numeric/filter-by-range';

export function expressionEvalForSizeDomain(operators) {
    let extremes = operators.extremes,
        schema = this.config.domain.operators,
        { min, max, base } = schema,
        { sortedRanges, filteredStops } = operators,
        domain = extremes;

    if (sortedRanges) {
        return d3_merge(sortedRanges);
    }

    if (schema.categories) {
        return schema.categories;
    }

    if (defined(base)) {
        domain = d3_extent([...domain, base]);
    }

    if (defined(min)) {
        domain[0] = min;
    }

    if (defined(max)) {
        domain[domain.length - 1] = max;
    }

    if (filteredStops) {
        domain = spliceMinMaxToArray(filteredStops, pick(min, domain[0]) || 0, pick(max, domain[domain.length - 1]) || 0);
    }

    return domain;
}

ScaleRegistry.add('size.evalDomain', expressionEvalForSizeDomain);
